import { useState, useEffect } from 'react'
import { useAuth } from '../../contexts/AuthContext'
import ProfilePicker from '../ProfilePicker'

function ProfileSettings() {
    const { user } = useAuth()
    const [formData, setFormData] = useState({
        name: '',
        profile_image: '',
        currentPassword: '',
        newPassword: ''
    })
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState('')
    const [success, setSuccess] = useState('')

    useEffect(() => {
        if (user) {
            setFormData(prev => ({
                ...prev,
                name: user.name,
                profile_image: user.profile_image || ''
            }))
        }
    }, [user])

    const handleSubmit = async (e) => {
        e.preventDefault()
        setError('')
        setSuccess('')
        setLoading(true)

        try {
            const res = await fetch('/api/auth/profile', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: formData.name,
                    profile_image: formData.profile_image,
                    password: formData.newPassword || undefined
                })
            })
            const data = await res.json()

            if (data.success) {
                setSuccess('Profile updated successfully!')
                // Ideally update context, but reload works for now for full refresh
                window.location.reload()
            } else {
                setError(data.message || 'Update failed')
            }
        } catch (err) {
            setError('Connection error')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div style={{ display: 'flex', height: '100%' }}>
            {/* Profile Picture Area */}
            <div className="settings-profile-sidebar">
                <div className="settings-avatar">
                    {formData.profile_image ? (
                        <img src={formData.profile_image} alt="Preview" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    ) : (
                        <span style={{ fontSize: '40px', color: 'var(--text-secondary)', opacity: 0.5 }}>?</span>
                    )}
                </div>
                <div style={{ width: '100%' }}>
                    <label className="settings-label-sm">Change Avatar</label>
                    <ProfilePicker
                        selectedImage={formData.profile_image}
                        onSelect={(img) => setFormData({ ...formData, profile_image: img })}
                    />
                </div>
            </div>

            {/* Profile Form */}
            <div style={{ flex: 1, padding: '28px' }}>
                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '18px', height: '100%' }}>
                    {error && <div className="error-message">{error}</div>}
                    {success && <div className="status-badge completed" style={{ display: 'block', textAlign: 'center' }}>{success}</div>}

                    <div className="form-group">
                        <label className="form-label">Full Name</label>
                        <input
                            type="text"
                            className="form-input"
                            value={formData.name}
                            onChange={e => setFormData({ ...formData, name: e.target.value })}
                            required
                        />
                    </div>

                    <div style={{ borderTop: '1px solid var(--border-layer-1)', margin: '4px 0' }}></div>

                    <div className="form-group">
                        <label className="form-label">New Password (optional)</label>
                        <input
                            type="password"
                            className="form-input"
                            placeholder="Leave blank to keep current"
                            value={formData.newPassword}
                            onChange={e => setFormData({ ...formData, newPassword: e.target.value })}
                        />
                    </div>

                    <div style={{ display: 'flex', gap: '12px', marginTop: 'auto', paddingTop: '16px' }}>
                        <button type="submit" className="btn-primary" disabled={loading} style={{ flex: 1 }}>
                            {loading ? 'Saving...' : 'Save Changes'}
                        </button>
                    </div>
                </form>
            </div>

            <style>{`
                .settings-profile-sidebar {
                    width: 260px;
                    background: var(--glass-layer-1);
                    border-right: 1px solid var(--border-layer-1);
                    padding: 32px 20px;
                    display: flex; flex-direction: column; align-items: center;
                }
                .settings-avatar {
                    width: 120px; height: 120px; border-radius: 50%;
                    background: var(--glass-layer-2); margin-bottom: 24px;
                    border: 4px solid var(--border-layer-2); overflow: hidden;
                    box-shadow: var(--shadow-layer-3);
                    display: flex; align-items: center; justify-content: center;
                }
                .settings-label-sm {
                   font-size: 13px; font-weight: 500; color: var(--text-secondary);
                   margin-bottom: 12px; display: block; text-align: center;
                }
                
                .form-group { display: flex; flex-direction: column; gap: 8px; }
                .form-label { font-size: 13px; font-weight: 500; color: var(--text-secondary); }
                .form-input {
                    padding: 12px 16px; border-radius: 10px;
                    background: var(--glass-layer-1);
                    border: 1px solid var(--border-layer-2);
                    color: var(--text-primary); font-size: 14px; outline: none;
                    transition: all 0.2s;
                }
                .form-input:focus {
                    background: var(--glass-layer-2);
                    border-color: var(--primary-color);
                    box-shadow: 0 0 0 3px rgba(102,126,234,0.15);
                }
                .error-message {
                    padding: 10px; border-radius: 8px; background: rgba(255,59,48,0.1);
                    border: 1px solid rgba(255,59,48,0.2); color: #ff3b30; font-size: 13px;
                }
                .status-badge.completed {
                    padding: 10px; border-radius: 8px; background: rgba(52,199,89,0.1);
                    border: 1px solid rgba(52,199,89,0.2); color: #34c759; font-size: 13px;
                }
                .btn-primary {
                    padding: 10px 20px; border-radius: 10px; border: none;
                    background: var(--primary-gradient);
                    color: white; font-weight: 600; font-size: 13px; cursor: pointer;
                    box-shadow: var(--shadow-layer-2); transition: opacity 0.2s;
                }
                .btn-primary:active { opacity: 0.8; transform: scale(0.98); }
            `}</style>
        </div>
    )
}

export default ProfileSettings
